'use client'
import { useEffect, useState } from 'react'
import { createClient } from '@/lib/supabase/client'

const LOGO_SRC = 'data:image/png;base64,'

export default function ArtistDetailPage({ params }: { params: { id: string } }) {
  const [artist, setArtist] = useState<any>(null)
  const [records, setRecords] = useState<any[]>([])
  const [statements, setStatements] = useState<any[]>([])
  const [loading, setLoading] = useState(true)
  const [userEmail, setUserEmail] = useState('')

  useEffect(() => {
    async function load() {
      const supabase = createClient()
      const { data: { session } } = await supabase.auth.getSession()
      if (!session) { window.location.href = '/auth/login'; return }

      const { data: profile } = await supabase.from('profiles').select('role').eq('id', session.user.id).single()
      if (profile?.role !== 'admin') { window.location.href = '/artist/dashboard'; return }
      setUserEmail(session.user.email || '')

      const [{ data: artistData }, { data: stmts }] = await Promise.all([
        supabase.from('artists').select('*').eq('id', params.id).single(),
        supabase.from('royalty_statements').select('*').eq('artist_id', params.id).order('created_at', { ascending: false }),
      ])

      if (!artistData) { window.location.href = '/admin/artists'; return }
      setArtist(artistData)
      setStatements(stmts || [])

      // Paginate records
      const allRecs: any[] = []
      let page = 0
      while (true) {
        const { data: chunk } = await supabase
          .from('royalty_records')
          .select('period,platform,country,streams,revenue,track_title,release_title')
          .eq('artist_id', params.id)
          .range(page * 1000, (page + 1) * 1000 - 1)
        if (!chunk || chunk.length === 0) break
        allRecs.push(...chunk)
        if (chunk.length < 1000) break
        page++
      }
      setRecords(allRecs)
      setLoading(false)
    }
    load()
  }, [params.id])

  async function logout() { await createClient().auth.signOut(); window.location.href = '/auth/login' }

  if (loading) return (
    <div style={{ minHeight:'100vh', display:'flex', alignItems:'center', justifyContent:'center', background:'#030a1c' }}>
      <div style={{ color:'rgba(125,163,252,0.5)', fontFamily:"'DM Mono',monospace", fontSize:12, letterSpacing:3 }}>LOADING...</div>
    </div>
  )

  const totalRev = records.reduce((s, r) => s + Number(r.revenue || 0), 0)
  const totalStr = records.reduce((s, r) => s + (r.streams || 0), 0)

  const byPlatform: Record<string, { rev: number; str: number }> = {}
  for (const r of records) {
    if (!r.platform) continue
    if (!byPlatform[r.platform]) byPlatform[r.platform] = { rev: 0, str: 0 }
    byPlatform[r.platform].rev += Number(r.revenue || 0)
    byPlatform[r.platform].str += r.streams || 0
  }
  const platforms = Object.entries(byPlatform).sort((a, b) => b[1].rev - a[1].rev)

  const byTrack: Record<string, { rev: number; str: number }> = {}
  for (const r of records) {
    const k = r.track_title || r.release_title || 'Unknown'
    if (!byTrack[k]) byTrack[k] = { rev: 0, str: 0 }
    byTrack[k].rev += Number(r.revenue || 0)
    byTrack[k].str += r.streams || 0
  }
  const tracks = Object.entries(byTrack).sort((a, b) => b[1].rev - a[1].rev).slice(0, 10)

  const PAL = ['#93c5fd','#6ee7b7','#c4b5fd','#fde68a','#f9a8d4','#67e8f9','#86efac','#fca5a5']
  const mono = "'DM Mono',monospace"
  const sans = "'DM Sans',sans-serif"
  const card: React.CSSProperties = { background:'rgba(255,255,255,0.04)', border:'1px solid rgba(255,255,255,0.08)', borderRadius:14, overflow:'hidden' }

  const nav = [
    { href:'/admin/dashboard', label:'Dashboard', icon:'📊' },
    { href:'/admin/artists', label:'Artists', icon:'🎤', active:true },
    { href:'/admin/upload', label:'Upload Reports', icon:'📂' },
    { href:'/admin/statements', label:'Statements', icon:'💸' },
  ]

  return (
    <div style={{ minHeight:'100vh', background:'#030a1c', backgroundImage:'radial-gradient(ellipse 120% 80% at 70% -20%, #0a2a7a 0%, #030a1c 60%)', fontFamily:sans }}>
      <header style={{ display:'flex', alignItems:'center', justifyContent:'space-between', padding:'0 32px', height:60, borderBottom:'1px solid rgba(255,255,255,0.08)', background:'rgba(3,10,28,0.97)', position:'sticky', top:0, zIndex:100 }}>
        <div style={{ display:'flex', alignItems:'center', gap:10 }}>
          <img src={LOGO_SRC} alt="MIDDLE BEATS" style={{ height:22, display:'block' }}/>
          <span style={{ fontSize:9, background:'rgba(59,130,246,0.15)', color:'#93c5fd', padding:'3px 9px', borderRadius:4, fontFamily:mono, letterSpacing:3, border:'1px solid rgba(59,130,246,0.2)' }}>ADMIN</span>
        </div>
        <div style={{ display:'flex', alignItems:'center', gap:14 }}>
          <span style={{ fontFamily:mono, fontSize:11, color:'rgba(255,255,255,0.3)' }}>{userEmail}</span>
          <button onClick={logout} style={{ background:'transparent', border:'1px solid rgba(255,255,255,0.1)', borderRadius:8, padding:'5px 14px', color:'rgba(255,255,255,0.4)', fontFamily:mono, fontSize:10, cursor:'pointer', letterSpacing:1 }}>SIGN OUT</button>
        </div>
      </header>

      <div style={{ display:'flex', minHeight:'calc(100vh - 60px)' }}>
        <aside style={{ width:210, borderRight:'1px solid rgba(255,255,255,0.07)', padding:'16px 0', background:'rgba(3,10,28,0.6)', flexShrink:0 }}>
          {nav.map(item => (
            <a key={item.href} href={item.href} style={{ display:'flex', alignItems:'center', gap:12, padding:'10px 22px', fontSize:13, color: item.active ? '#fff' : 'rgba(255,255,255,0.45)', textDecoration:'none', borderLeft: item.active ? '2px solid #2563eb' : '2px solid transparent', background: item.active ? 'rgba(37,99,235,0.1)' : 'transparent', fontFamily:sans }}>
              <span>{item.icon}</span>{item.label}
            </a>
          ))}
        </aside>

        <main style={{ flex:1, padding:'28px 32px', overflowY:'auto' as const }}>
          <a href="/admin/artists" style={{ fontFamily:mono, fontSize:11, color:'rgba(255,255,255,0.4)', textDecoration:'none', display:'inline-block', marginBottom:20 }}>← Back to Artists</a>

          <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:24, flexWrap:'wrap' as const, gap:12 }}>
            <div style={{ display:'flex', alignItems:'center', gap:14 }}>
              <div style={{ width:48, height:48, borderRadius:12, background:'linear-gradient(135deg,#2563eb,#06b6d4)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:20, fontWeight:700 }}>{artist.name.charAt(0)}</div>
              <div>
                <h1 style={{ fontSize:22, fontWeight:700, color:'#fff', margin:0, fontFamily:"'Syne',sans-serif" }}>{artist.name}</h1>
                <div style={{ fontFamily:mono, fontSize:11, color:'rgba(255,255,255,0.35)', marginTop:3 }}>{artist.email}</div>
              </div>
            </div>
            <span style={{ fontFamily:mono, fontSize:9, padding:'4px 12px', borderRadius:6, border:'1px solid', letterSpacing:1, ...(artist.is_active ? { color:'#86efac', borderColor:'rgba(134,239,172,0.3)', background:'rgba(134,239,172,0.08)' } : { color:'rgba(255,255,255,0.3)', borderColor:'rgba(255,255,255,0.1)', background:'rgba(255,255,255,0.04)' }) }}>
              {artist.is_active ? '● ACTIVE' : '○ INACTIVE'}
            </span>
          </div>

          {/* KPIs */}
          <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:12, marginBottom:24 }}>
            {[
              { label:'Revenue', value:'$'+totalRev.toFixed(2), color:'#93c5fd' },
              { label:'Streams', value:totalStr.toLocaleString(), color:'#c4b5fd' },
              { label:'Platforms', value:platforms.length, color:'#6ee7b7' },
              { label:'Statements', value:statements.length, color:'#fde68a' },
            ].map(k => (
              <div key={k.label} style={{ ...card, padding:'18px 20px' }}>
                <div style={{ fontFamily:mono, fontSize:9, letterSpacing:2, color:'rgba(255,255,255,0.35)', textTransform:'uppercase' as const, marginBottom:8 }}>{k.label}</div>
                <div style={{ fontSize:26, fontWeight:700, color:k.color, fontFamily:"'Syne',sans-serif" }}>{k.value}</div>
              </div>
            ))}
          </div>

          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:16, marginBottom:16 }}>
            {/* Platforms */}
            <div style={card}>
              <div style={{ padding:'12px 18px', borderBottom:'1px solid rgba(255,255,255,0.07)', fontFamily:mono, fontSize:9, letterSpacing:2, color:'rgba(255,255,255,0.35)', textTransform:'uppercase' as const }}>Revenue by Platform</div>
              {platforms.slice(0,8).map(([name, d], i) => {
                const pct = Math.round((d.rev / (platforms[0][1].rev || 1)) * 100)
                return (
                  <div key={name} style={{ display:'flex', alignItems:'center', gap:10, padding:'10px 18px', borderBottom:'1px solid rgba(255,255,255,0.04)' }}>
                    <div style={{ width:7, height:7, borderRadius:'50%', background:PAL[i%PAL.length], flexShrink:0 }}/>
                    <div style={{ flex:1, minWidth:0 }}>
                      <div style={{ fontSize:12, fontWeight:500, color:'#fff', marginBottom:4, whiteSpace:'nowrap' as const, overflow:'hidden', textOverflow:'ellipsis' }}>{name}</div>
                      <div style={{ height:3, background:'rgba(255,255,255,0.06)', borderRadius:2 }}>
                        <div style={{ height:'100%', borderRadius:2, background:PAL[i%PAL.length], width:pct+'%' }}/>
                      </div>
                    </div>
                    <div style={{ fontFamily:mono, fontSize:11, color:PAL[i%PAL.length], fontWeight:600, flexShrink:0 }}>${d.rev.toFixed(4)}</div>
                  </div>
                )
              })}
              {!platforms.length && <div style={{ padding:24, textAlign:'center' as const, color:'rgba(255,255,255,0.2)', fontSize:12 }}>No data</div>}
            </div>

            {/* Top Tracks */}
            <div style={card}>
              <div style={{ padding:'12px 18px', borderBottom:'1px solid rgba(255,255,255,0.07)', fontFamily:mono, fontSize:9, letterSpacing:2, color:'rgba(255,255,255,0.35)', textTransform:'uppercase' as const }}>Top Tracks</div>
              {tracks.map(([name, d], i) => {
                const pct = Math.round((d.rev / (tracks[0][1].rev || 1)) * 100)
                return (
                  <div key={name} style={{ display:'flex', alignItems:'center', gap:10, padding:'10px 18px', borderBottom:'1px solid rgba(255,255,255,0.04)' }}>
                    <span style={{ fontFamily:mono, fontSize:10, color:'rgba(255,255,255,0.2)', width:16, textAlign:'right' as const }}>{i+1}</span>
                    <div style={{ flex:1, minWidth:0 }}>
                      <div style={{ fontSize:12, fontWeight:500, color:'#fff', marginBottom:4, whiteSpace:'nowrap' as const, overflow:'hidden', textOverflow:'ellipsis' }}>{name}</div>
                      <div style={{ height:3, background:'rgba(255,255,255,0.06)', borderRadius:2 }}>
                        <div style={{ height:'100%', borderRadius:2, background:'#c4b5fd', width:pct+'%' }}/>
                      </div>
                    </div>
                    <div style={{ fontFamily:mono, fontSize:11, color:'#c4b5fd', fontWeight:600, flexShrink:0 }}>{d.str.toLocaleString()}</div>
                  </div>
                )
              })}
              {!tracks.length && <div style={{ padding:24, textAlign:'center' as const, color:'rgba(255,255,255,0.2)', fontSize:12 }}>No data</div>}
            </div>
          </div>

          {/* Statements */}
          <div style={card}>
            <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', padding:'12px 18px', borderBottom:'1px solid rgba(255,255,255,0.07)' }}>
              <span style={{ fontFamily:mono, fontSize:9, letterSpacing:2, color:'rgba(255,255,255,0.35)', textTransform:'uppercase' as const }}>Royalty Statements</span>
              <a href="/admin/statements" style={{ fontFamily:mono, fontSize:11, color:'#93c5fd', textDecoration:'none' }}>Generate →</a>
            </div>
            {statements.map(s => (
              <div key={s.id} style={{ display:'flex', alignItems:'center', justifyContent:'space-between', padding:'12px 18px', borderBottom:'1px solid rgba(255,255,255,0.04)' }}>
                <div>
                  <div style={{ fontFamily:mono, fontSize:12, fontWeight:600, color:'#fff' }}>{s.period}</div>
                  <div style={{ fontFamily:mono, fontSize:10, color:'rgba(255,255,255,0.3)', marginTop:2 }}>{new Date(s.created_at).toLocaleDateString()}</div>
                </div>
                <div style={{ display:'flex', alignItems:'center', gap:12 }}>
                  <div style={{ fontFamily:mono, fontSize:13, color:'#93c5fd', fontWeight:700 }}>${Number(s.total_revenue).toFixed(2)}</div>
                  <span style={{ fontFamily:mono, fontSize:9, padding:'2px 8px', borderRadius:4, background: s.status==='paid' ? 'rgba(134,239,172,0.1)' : s.status==='sent' ? 'rgba(147,197,253,0.1)' : 'rgba(253,230,138,0.1)', color: s.status==='paid' ? '#86efac' : s.status==='sent' ? '#93c5fd' : '#fde68a', border:'1px solid', borderColor: s.status==='paid' ? 'rgba(134,239,172,0.2)' : s.status==='sent' ? 'rgba(147,197,253,0.2)' : 'rgba(253,230,138,0.2)' }}>{s.status.toUpperCase()}</span>
                </div>
              </div>
            ))}
            {!statements.length && <div style={{ padding:24, textAlign:'center' as const, color:'rgba(255,255,255,0.2)', fontSize:12, fontFamily:mono }}>No statements yet</div>}
          </div>
        </main>
      </div>
    </div>
  )
}
